import { Component, OnInit } from '@angular/core';
import { ActivatedRoute, Router } from '@angular/router';
import { CharacterService } from '../../services/character.service';
import { Character } from '../../models/character';

// Interface para atributos que permite indexação por string
interface AttributesMap {
  [key: string]: number;
}

// Interface para a resposta da API
interface ApiCharacter {
  id?: string;
  userId?: string;
  name: string;
  race?: string;
  charClass?: string;
  attributes?: {
    strength: number;
    dexterity: number;
    constitution: number;
    intelligence: number;
    wisdom: number;
    charisma: number;
  };
  skills?: any;
  progression?: {
    level?: number;
    experience?: number;
    alignment?: string;
  };
  hitPoints?: {
    maximum?: number;
    current?: number;
    temporary?: number;
  };
  [key: string]: any; // Para outras propriedades
}

@Component({
  selector: 'app-ficha-de-personagem',
  templateUrl: './ficha-de-personagem.component.html',
  styleUrls: ['./ficha-de-personagem.component.css']
})
export class FichaDePersonagemComponent implements OnInit {
  personagem: Character | null = null;
  apiPersonagem: ApiCharacter | null = null;
  isLoading: boolean = false;
  isError: boolean = false;
  errorMessage: string = '';
  atributoNomes: string[] = ['strength', 'dexterity', 'constitution', 'intelligence', 'wisdom', 'charisma'];
  nomesAtributosPortugues: {[key: string]: string} = {
    'strength': 'Força',
    'dexterity': 'Destreza',
    'constitution': 'Constituição',
    'intelligence': 'Inteligência',
    'wisdom': 'Sabedoria',
    'charisma': 'Carisma'
  };

  constructor(
    private route: ActivatedRoute,
    private router: Router,
    public characterService: CharacterService
  ) { }

  ngOnInit(): void {
    this.carregarPersonagem();
  }

  carregarPersonagem(): void {
    this.isLoading = true;
    const id = this.route.snapshot.paramMap.get('id');

    if (!id) {
      this.isError = true;
      this.errorMessage = 'ID do personagem não encontrado';
      this.isLoading = false;
      return;
    }

    this.characterService.getCharacter(id).subscribe({
      next: (apiResponse: any) => {
        console.log('Resposta da API:', apiResponse);

        // Armazenar resposta original da API
        this.apiPersonagem = apiResponse;

        // Criar uma adaptação para o nosso modelo Character
        this.personagem = this.adaptApiResponseToCharacter(apiResponse);

        console.log('Personagem adaptado:', this.personagem);

        this.isLoading = false;
      },
      error: (error) => {
        this.isError = true;
        this.errorMessage = 'Erro ao carregar detalhes do personagem: ' + (error.error?.message || error.message || 'Erro desconhecido');
        this.isLoading = false;
        console.error('Erro ao carregar personagem:', error);
      }
    });
  }

  // Adapta a resposta da API ao formato esperado pelo nosso modelo
  adaptApiResponseToCharacter(apiChar: ApiCharacter): Character {
    // Valores padrão para campos obrigatórios
    const defaultAttributes = {
      strength: 10,
      dexterity: 10,
      constitution: 10,
      intelligence: 10,
      wisdom: 10,
      charisma: 10
    };

    const defaultHitPoints = {
      maximum: 10,
      current: 10,
      temporary: 0
    };

    // Adaptação do objeto
    return {
      id: apiChar.id || '',
      userId: apiChar.userId || '',
      name: apiChar.name || 'Sem Nome',
      level: apiChar.progression?.level || 1,
      experience: apiChar.progression?.experience || 0,

      // Converter strings de raça e classe para o formato do nosso modelo
      race: {
        index: apiChar.race?.toLowerCase() || '',
        name: this.formatRaceName(apiChar.race) || 'Desconhecida',
        url: ''
      },
      class: {
        index: apiChar.charClass?.toLowerCase() || '',
        name: this.formatClassName(apiChar.charClass) || 'Desconhecida',
        url: ''
      },

      // Usar os atributos da resposta ou valores padrão
      attributes: apiChar.attributes || defaultAttributes,

      // Informações de campanha
      background: apiChar['background'] || '',
      alignment: apiChar.progression?.alignment || 'Neutro',

      // Características derivadas
      hitPoints: {
        maximum: apiChar.hitPoints?.maximum || defaultHitPoints.maximum,
        current: apiChar.hitPoints?.current || defaultHitPoints.current,
        temporary: apiChar.hitPoints?.temporary || defaultHitPoints.temporary
      },

      armorClass: apiChar['armorClass'] || 10,
      initiative: apiChar['initiative'] || 0,
      speed: apiChar['speed'] || 30,

      // Proficiências - transformar o objeto de habilidades em listas
      proficiencies: this.extractProficiencies(apiChar.skills),

      // Equipamentos (se disponível na API)
      equipment: apiChar['equipment'] || [],

      // Magias (se disponível na API)
      spells: apiChar['spells'] || [],

      // Outras informações
      features: apiChar['features'] || [],

      // Para histórico de alterações
      createdAt: apiChar['createdAt'] ? new Date(apiChar['createdAt']) : new Date(),
      updatedAt: apiChar['updatedAt'] ? new Date(apiChar['updatedAt']) : new Date()
    };
  }

  // Formatar o nome da raça para exibição
  formatRaceName(race: string | undefined): string {
    if (!race) return 'Desconhecida';

    // Converter de ELFO para Elfo
    return race.toLowerCase().replace(/\b\w/g, (l) => l.toUpperCase());
  }

  // Formatar o nome da classe para exibição
  formatClassName(charClass: string | undefined): string {
    if (!charClass) return 'Desconhecida';

    const classMap: {[key: string]: string} = {
      'BARBARO': 'Bárbaro',
      'BARDO': 'Bardo',
      'BRUXO': 'Bruxo',
      'CLERIGO': 'Clérigo',
      'DRUIDA': 'Druida',
      'FEITICEIRO': 'Feiticeiro',
      'GUERREIRO': 'Guerreiro',
      'LADINO': 'Ladino',
      'MAGO': 'Mago',
      'MONGE': 'Monge',
      'PALADINO': 'Paladino',
      'PATRULHEIRO': 'Patrulheiro'
    };

    return classMap[charClass] || charClass.toLowerCase().replace(/\b\w/g, (l) => l.toUpperCase());
  }

  // Extrair proficiências do objeto de habilidades
  extractProficiencies(skills: any): any {
    if (!skills) {
      return {
        savingThrows: [],
        skills: [],
        languages: [],
        tools: [],
        weapons: [],
        armors: []
      };
    }

    // Mapeamento de propriedades para nomes legíveis
    const savingThrowMap: {[key: string]: string} = {
      stStrength: 'Força',
      stDexterity: 'Destreza',
      stConstitution: 'Constituição',
      stIntelligence: 'Inteligência',
      stWisdom: 'Sabedoria',
      stCharisma: 'Carisma'
    };

    const skillMap: {[key: string]: string} = {
      acrobatics: 'Acrobacia',
      animalHandling: 'Adestrar Animais',
      arcana: 'Arcanismo',
      athletics: 'Atletismo',
      deception: 'Enganação',
      history: 'História',
      insight: 'Intuição',
      intimidation: 'Intimidação',
      investigation: 'Investigação',
      medicine: 'Medicina',
      nature: 'Natureza',
      perception: 'Percepção',
      performance: 'Atuação',
      persuasion: 'Persuasão',
      religion: 'Religião',
      sleightOfHand: 'Prestidigitação',
      stealth: 'Furtividade',
      survival: 'Sobrevivência'
    };

    // Extrair salvaguardas
    const savingThrows = Object.entries(savingThrowMap)
      .filter(([key]) => skills[key])
      .map(([_, name]) => name);

    // Extrair habilidades
    const skillsArray = Object.entries(skillMap)
      .filter(([key]) => skills[key])
      .map(([_, name]) => name);

    return {
      savingThrows,
      skills: skillsArray,
      languages: skills['languages'] || [],
      tools: skills['tools'] || [],
      weapons: skills['weapons'] || [],
      armors: skills['armors'] || []
    };
  }

  voltarParaLista(): void {
    this.router.navigate(['/personagens']);
  }

  editarPersonagem(): void {
    if (this.personagem) {
      this.router.navigate(['/personagens/editar', this.personagem.id]);
    }
  }

  temItens(array: any[] | undefined | null): boolean {
    return Array.isArray(array) && array.length > 0;
  }

  // Método helper para acessar atributos com segurança de tipo
  getAttributeValue(atributo: string): number {
    if (!this.personagem || !this.personagem.attributes) return 0;

    return (this.personagem.attributes as unknown as AttributesMap)[atributo] || 0;
  }
}
<app-header></app-header>

<section class="ficha-container">
  <!-- Loading spinner -->
  <div *ngIf="isLoading" class="loading-overlay">
    <app-loading></app-loading>
  </div>

  <!-- Mensagem de erro -->
  <div *ngIf="isError" class="error-message">
    <p>{{ errorMessage }}</p>
    <button (click)="isError = false">Fechar</button>
  </div>

  <div *ngIf="personagem && !isLoading" class="ficha-content">
    <div class="ficha-header">
      <h1>{{ personagem.name }}</h1>
      <div class="ficha-basic-info">
        <span class="race-class">{{ personagem.race?.name || 'Raça Desconhecida' }} {{ personagem.class?.name || 'Classe Desconhecida' }}</span>
        <span class="level">Nível {{ personagem.level || 1 }}</span>
      </div>
    </div>

    <div class="ficha-actions">
      <button class="btn-voltar" (click)="voltarParaLista()">← Voltar para Lista</button>
      <button class="btn-editar" (click)="editarPersonagem()">Editar Personagem</button>
    </div>

    <div class="ficha-grid">
      <!-- Informações básicas -->
      <div class="ficha-card info-card">
        <h2>Informações Básicas</h2>
        <div class="info-content">
          <p><strong>Nome:</strong> {{ personagem.name }}</p>
          <p><strong>Raça:</strong> {{ personagem.race?.name || 'Raça Desconhecida' }}</p>
          <p><strong>Classe:</strong> {{ personagem.class?.name || 'Classe Desconhecida' }}</p>
          <p><strong>Nível:</strong> {{ personagem.level || 1 }}</p>
          <p><strong>Antecedente:</strong> {{ personagem.background || 'Não definido' }}</p>
          <p><strong>Alinhamento:</strong> {{ personagem.alignment || 'Não definido' }}</p>
        </div>
      </div>

      <!-- Atributos -->
      <div class="ficha-card attributes-card">
        <h2>Atributos</h2>
        <div class="attributes-grid">
          <div class="attribute" *ngFor="let atributo of atributoNomes">
            <div class="attribute-name">{{ nomesAtributosPortugues[atributo] }}</div>
            <div class="attribute-value">{{ getAttributeValue(atributo) }}</div>
            <div class="attribute-modifier">
              {{ characterService.calculateAttributeModifier(getAttributeValue(atributo)) >= 0 ? '+' : '' }}{{ characterService.calculateAttributeModifier(getAttributeValue(atributo)) }}
            </div>
          </div>
        </div>
      </div>

      <!-- Combate -->
      <div class="ficha-card combat-card">
        <h2>Combate</h2>
        <div class="combat-stats">
          <div class="combat-stat">
            <div class="stat-name">Classe de Armadura</div>
            <div class="stat-value">{{ personagem.armorClass || 10 }}</div>
          </div>
          <div class="combat-stat">
            <div class="stat-name">Iniciativa</div>
            <div class="stat-value">{{ (personagem.initiative || 0) >= 0 ? '+' : '' }}{{ personagem.initiative || 0 }}</div>
          </div>
          <div class="combat-stat">
            <div class="stat-name">Pontos de Vida</div>
            <div class="stat-value">
              {{ personagem.hitPoints?.current || 0 }} / {{ personagem.hitPoints?.maximum || 0 }}
            </div>
          </div>
        </div>
      </div>

      <!-- Proficiências -->
      <div class="ficha-card proficiencies-card" *ngIf="personagem.proficiencies && temItens(personagem.proficiencies.savingThrows)">
        <h2>Proficiências</h2>
        <div class="proficiencies-content">
          <div *ngIf="temItens(personagem.proficiencies.savingThrows)">
            <h3>Salvaguardas</h3>
            <ul>
              <li *ngFor="let save of personagem.proficiencies.savingThrows">{{ save }}</li>
            </ul>
          </div>
          <div *ngIf="temItens(personagem.proficiencies.skills)">
            <h3>Perícias</h3>
            <ul>
              <li *ngFor="let skill of personagem.proficiencies.skills">{{ skill }}</li>
            </ul>
          </div>
          <div *ngIf="temItens(personagem.proficiencies.languages)">
            <h3>Idiomas</h3>
            <ul>
              <li *ngFor="let language of personagem.proficiencies.languages">{{ language }}</li>
            </ul>
          </div>
          <div *ngIf="temItens(personagem.proficiencies.weapons)">
            <h3>Armas</h3>
            <ul>
              <li *ngFor="let weapon of personagem.proficiencies.weapons">{{ weapon }}</li>
            </ul>
          </div>
          <div *ngIf="temItens(personagem.proficiencies.armors)">
            <h3>Armaduras</h3>
            <ul>
              <li *ngFor="let armor of personagem.proficiencies.armors">{{ armor }}</li>
            </ul>
          </div>
          <div *ngIf="temItens(personagem.proficiencies.tools)">
            <h3>Ferramentas</h3>
            <ul>
              <li *ngFor="let tool of personagem.proficiencies.tools">{{ tool }}</li>
            </ul>
          </div>
        </div>
      </div>

      <!-- Equipamentos -->
      <div class="ficha-card equipment-card" *ngIf="temItens(personagem.equipment)">
        <h2>Equipamento</h2>
        <ul class="equipment-list">
          <li *ngFor="let item of personagem.equipment">
            {{ item.name }} {{ item.quantity > 1 ? '(' + item.quantity + ')' : '' }}
          </li>
        </ul>
      </div>

      <!-- Magias -->
      <div class="ficha-card spells-card" *ngIf="temItens(personagem.spells)">
        <h2>Magias</h2>
        <ul class="spells-list">
          <li *ngFor="let spell of personagem.spells">{{ spell.name }} (Nível {{ spell.level }})</li>
        </ul>
      </div>
    </div>
  </div>
</section>

<app-footer></app-footer>
